INSERT INTO public.questions VALUES ('e7c8a5c8-f0b8-41ac-aab1-5f0e51a31ecb', '3bfa1e7b-e2b1-4ec4-bbbe-7666750da553', 'matrix', 'Questions 17-20', '', '<p>Label the map below.</p>
<p><img src="data:image/png;base64," width="615" height="534"></p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "Admin Tent", "correctCategoryLetter": "C"}, {"itemText": " Lost Property", "correctCategoryLetter": "E"}, {"itemText": "Sandcastle Competition", "correctCategoryLetter": "B"}, {"itemText": "First Aid", "correctCategoryLetter": "F"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}, {"categoryText": "I", "categoryLetter": "I"}]}', 'null', 1);
INSERT INTO public.questions VALUES ('93b5bb12-8ebb-41da-bae3-ab27276630bd', 'af2b8a94-7dce-4854-b4e6-49b527a0ec0c', 'radio', 'Questions 23–26', NULL, '<p>Choose <strong>TRUE</strong> if the statement agrees with the information given in the text, choose <strong>FALSE</strong> if the statement contradicts the information, or choose <strong>NOT GIVEN</strong> if there is no information on this.</p>
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "In the 1850s, trained artists were reluctant to take up photography."}, {"correct": 2, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Many photographers felt the need to learn certain techniques from taking art courses."}, {"correct": 1, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "Photography brought the demand for portrait painting to an end."}, {"correct": 0, "options": [{"content": "TRUE"}, {"content": "FALSE"}, {"content": "NOT GIVEN"}], "question": "With the advent of photography, some painters no longer concerned themselves with accuracy."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">Câu 23: In the 1850s, trained artists were reluctant to take up photography.</strong></p>\n<ul data-path-to-node=\"26\">\n<li>\n<p data-path-to-node=\"26,0,0\"><strong data-path-to-node=\"26,0,0\" data-index-in-node=\"0\">Đáp án:</strong> FALSE</p>\n</li>\n<li>\n<p data-path-to-node=\"26,1,0\"><strong data-path-to-node=\"26,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…the development of the art of photography in the late 1850s can be partly accounted for through the <strong data-path-to-node=\"26,1,0\" data-index-in-node=\"115\">increasing involvement of people trained as artists</strong>.” (Đoạn F)</p>\n</li>\n<li>\n<p data-path-to-node=\"26,2,0\"><strong data-path-to-node=\"26,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Văn bản nói rằng sự tham gia của các nghệ sĩ ngày càng tăng, trái ngược với ý kiến cho rằng họ “reluctant” (ngần ngại/miễn cưỡng).</p>\n</li>\n</ul>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">Câu 24: Many photographers felt the need to learn certain techniques from taking art courses.</strong></p>\n<ul data-path-to-node=\"28\">\n<li>\n<p data-path-to-node=\"28,0,0\"><strong data-path-to-node=\"28,0,0\" data-index-in-node=\"0\">Đáp án:</strong> NOT GIVEN</p>\n</li>\n<li>\n<p data-path-to-node=\"28,1,0\"><strong data-path-to-node=\"28,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> Không có thông tin.</p>\n</li>\n<li>\n<p data-path-to-node=\"28,2,0\"><strong data-path-to-node=\"28,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có nói về các nghệ sĩ chuyển sang làm nhiếp ảnh, nhưng không hề đề cập đến việc các nhiếp ảnh gia đi học các khóa học nghệ thuật để học kỹ thuật.</p>\n</li>\n</ul>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">Câu 25: Photography brought the demand for portrait painting to an end.</strong></p>\n<ul data-path-to-node=\"30\">\n<li>\n<p data-path-to-node=\"30,0,0\"><strong data-path-to-node=\"30,0,0\" data-index-in-node=\"0\">Đáp án:</strong> FALSE</p>\n</li>\n<li>\n<p data-path-to-node=\"30,1,0\"><strong data-path-to-node=\"30,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “This did not prevent a continuing hierarchy: the <strong data-path-to-node=\"30,1,0\" data-index-in-node=\"61\">painted portrait was still commissioned</strong> by the wealthy and the aristocracy.” (Đoạn F)</p>\n</li>\n<li>\n<p data-path-to-node=\"30,2,0\"><strong data-path-to-node=\"30,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Mặc dù nhiếp ảnh phổ biến hơn, giới thượng lưu vẫn tiếp tục đặt thuê vẽ chân dung. Do đó, nhu cầu vẽ chân dung không hề chấm dứt hoàn toàn.</p>\n</li>\n</ul>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">Câu 26: With the advent of photography, some painters no longer concerned themselves with accuracy.</strong></p>\n<ul data-path-to-node=\"32\">\n<li>\n<p data-path-to-node=\"32,0,0\"><strong data-path-to-node=\"32,0,0\" data-index-in-node=\"0\">Đáp án:</strong> TRUE</p>\n</li>\n<li>\n<p data-path-to-node=\"32,1,0\"><strong data-path-to-node=\"32,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…photography <strong data-path-to-node=\"32,1,0\" data-index-in-node=\"27\">released painting from its responsibility for literal depiction</strong>, allowing it to become more experimental.” (Đoạn G)</p>\n</li>\n<li>\n<p data-path-to-node=\"32,2,0\"><strong data-path-to-node=\"32,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Khi nhiếp ảnh làm tốt việc sao chép thực tế (accuracy/literal depiction), hội họa được “giải phóng” để tập trung vào các yếu tố sáng tạo khác thay vì chỉ quan tâm đến việc vẽ cho thật giống.</p>\n</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('3aadeaf2-9073-4cea-89a9-19f5a24444ef', 'd96d2ec4-17d6-40d7-a9a8-138c13df16aa', 'radio', 'Question 11-15', '', '<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text ">
<div class="">
<div class="s-component-content s-font-body">
<p>Choose the correct letter, A,B or C</p>
</div>
</div>
</div>
</div>
</div>
</div>
</div>
<div class="s-block-item s-repeatable-item s-block-sortable-item s-blog-post-section blog-section">
<div class="container">
<div class="sixteen columns">
<div class="s-blog-section-inner">
<div class="s-component s-text ">
<div class="">
<div class="s-component-content s-font-body">
<p><strong>Driving license in UK</strong></p>
</div>
</div>
</div>
</div>
</div>
</div>
</div>', 'multiple_choice', '[{"correct": 2, "options": [{"option_text": "A a medical report"}, {"option_text": "B a valid licence from another country"}, {"option_text": "C Current residency in the UK"}], "question": "What is the basic requirement for applying for a UK driving licence?"}, {"correct": 0, "options": [{"option_text": "A Applicants need to go to a recognised organisation"}, {"option_text": "B It is not always necessary for foreigners when applying for a UK licence"}, {"option_text": "C Applicants need to pay an extra fee for translation services"}], "question": "What is true about the translation of original licences?"}, {"correct": 1, "options": [{"option_text": "A Photos in which the applicant is wearing glasses"}, {"option_text": "B Photos with a cream background"}, {"option_text": "C Photos that are undersized"}], "question": "When applying for a UK licence, which type of photos will NOT be approved?"}, {"correct": 0, "options": [{"option_text": "A The process is too slow"}, {"option_text": "B The application form is confusing"}, {"option_text": "C Some of the steps are unnecessary"}], "question": "What does the speaker think of the licence checking service?"}, {"correct": 2, "options": [{"option_text": "A Choosing a quiet location"}, {"option_text": "B Visiting the nearest branch"}, {"option_text": "C Completing the forms online"}], "question": "What does the speaker recommend about making an application?"}]', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">SECTION 2: DRIVING LICENCES AND TRAFFIC CONDITIONS</strong></h3>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Edward:</strong> Hello, I’m Edward and I’m here to tell you about road conditions in various areas of the UK. I am also going to tell you about driver’s licenses in the UK.</p>\n<p id=\"p-rc_1255320846f8b4f5-142\" data-path-to-node=\"4\">If you have never had a driver’s licence or you have one from another country and you want to get a UK licence, <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"4\" data-index-in-node=\"112\">(11) you must be a UK resident [Answer: C]</strong></span>. <span class=\"citation-2373 citation-end-2373\">You will need to show a medical report when your UK licence needs to be renewed.</span></p>\n<p id=\"p-rc_1255320846f8b4f5-143\" data-path-to-node=\"5\"><span class=\"citation-2372 citation-end-2372\">If you are trying to translate your original foreign driving licence to apply for a UK licence, which is a must if you want to be able to driv</span>e here, <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"5\" data-index-in-node=\"150\">(12) you will need to visit an official agency [Answer: A – recognized organisation]</strong></span>. These are scattered throughout the London area and are well equipped to assist you with any questions you might have, and any services they offer are included in your license <span class=\"citation-2370 citation-2371 citation-end-2371\">fee. If you already have a translated licence but need some personal information updating, you do not need to pay for the update; they’ll do it for free.</span></p>\n<p id=\"p-rc_1255320846f8b4f5-144\" data-path-to-node=\"6\"><span class=\"citation-2368 citation-2369 citation-end-2369\">When you are getting a new driving licence, you may need to have a new photo taken as some photos </span><span class=\"citation-2368\">are rejected. It’s actually okay if your photo is too small since we can get it enlarged with our printer. </span><span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"6\" data-index-in-node=\"205\"><span class=\"citation-2368 citation-end-2368\">(</span>13) The majority of rejected photos are the ones that were taken with a cream backdrop [Answer: B]</strong></span>, instead of a monotone grey background. <span class=\"citation-2366 citation-2367 citation-end-2367\">We’ve now found that photos with the latter allow us to identify the licence holder much more easily. If you were wearing glasses on the previous photo, you don’t need to worry about it since it is still allowed.</span></p>\n<p id=\"p-rc_1255320846f8b4f5-145\" data-path-to-node=\"7\"><span class=\"citation-2364 citation-2365 citation-end-2365\">If you are not sure whether your previous licence is still valid then the licence checking service is for you. The procedures are qu</span><span class=\"citation-2364 citation-end-2364\">ite clear and you just have to follow them</span>. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"7\" data-index-in-node=\"176\">(14) Ideally I would like to see the process going faster, since it can take hours to finish [Answer: A – too slow]</strong></span>. <span class=\"citation-2362 citation-2363 citation-end-2363\">From my standpoint, it will help if all the applicants bring the necessary identification with them, then all they have to do is just fill in the forms accordingly step by step.</span></p>\n<p id=\"p-rc_1255320846f8b4f5-146\" data-path-to-node=\"8\"><span class=\"citation-2360 citation-2361 citation-end-2361\">I’m often asked whether I have a personal recommendation about the fastest or cheapest place to</span><span class=\"citation-2360 citation-end-2360\"> get all this done, but I think it really depends on where you are. They can all get busy at some point and when it is quiet at one branch it may be busy in another so take your pick. A</span>ll I would say is that there is absolutely no difference in price. It’s a standard fee the only advice I would give is that <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"8\" data-index-in-node=\"268\">(15) The quickest way to complete an application is to fill out the form on the internet [Answer: C]</strong></span>, and then bring a print copy with you to the agency location of your choice.</p>\n<hr data-path-to-node=\"9\">\n<h3 data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">TRAFFIC MANAGEMENT IN UK CITIES (Questions 16–20)</strong></h3>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Edward:</strong> Next, people frequently ask me what I think of the road conditions in some of our cities.</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">London</strong> is obviously the biggest, and busiest and there are lots of parking restrictions, one-way systems and so on. But on the whole, <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"12\" data-index-in-node=\"122\">(16) I find the traffic signs are very clear [Answer: A – Good signage]</strong>.</span></p>\n<p id=\"p-rc_1255320846f8b4f5-147\" data-path-to-node=\"13\">In <strong data-path-to-node=\"13\" data-index-in-node=\"3\">Edinburgh</strong>, most people use digital maps to get to know local traffic and road conditions in some of our cities<br>London is obviously the biggest and big and there are lots of parking restrictions one way systems and so on<br>but on the whole. I find the traffic signs are very clear in Edinburgh most people use digital maps to get to know local traffic and road conditions which can be estimated through different traffic flow lines. It is a city of lights—traffic lights—but <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"13\" data-index-in-node=\"135\">(17) they’re extremely efficient as they’re timed perfectly to get the traffic flowing smoothly [Answer: F – Effective traffic lights]</strong>.</span> <span class=\"citation-2359 citation-end-2359\">That’s important because pedestrian areas and crossings are always packed with people on foot which needs strong regulation.</span></p>\n<p id=\"p-rc_1255320846f8b4f5-148\" data-path-to-node=\"14\"><span class=\"citation-2358\">The City of </span><strong data-path-to-node=\"14\" data-index-in-node=\"12\"><span class=\"citation-2358\">Cardiff</span></strong><span class=\"citation-2358 citation-end-2358\"> has tackled traffic flow in a different way. It recently completed a road expansion scheme</span> and <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"14\" data-index-in-node=\"115\">(18) the extra lanes of the dual carriageway are easing congestion [Answer: G – Additional lanes]</strong>.</span></p>\n<p data-path-to-node=\"15\">It’s a similar story in <strong data-path-to-node=\"15\" data-index-in-node=\"24\">Manchester</strong>. Instead of going through the town centre, <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"15\" data-index-in-node=\"78\">(19) most vehicles choose ring roads so as to avoid the downtown congestion [Answer: D – Ring roads]</strong></span>. It can still happen though, so there’s a possibility that the city will introduce checkpoints where the police can intervene to direct traffic at peak periods..</p>\n<p data-path-to-node=\"16\">And finally, they say all roads lead to Rome, and you could say that about <strong data-path-to-node=\"16\" data-index-in-node=\"75\">Oxford</strong>. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"16\" data-index-in-node=\"83\">(20) I like the many options for getting in and out of the city because drivers can always find alternative routes [Answer: B – Multiple access roads]</strong>.</span></p>"}]', 0);
INSERT INTO public.questions VALUES ('fa17b038-82f5-408b-9837-8343a284dc2d', 'beff67df-f921-4b68-bc09-8ca8ac8e8684', 'checkbox', 'Questions 19 - 20', NULL, '<p>Choose <strong>TWO </strong>letters, A–E</p>
<p>Which <strong>TWO </strong>things should staff do when moving papers?</p>
', 'multiple_choice_many', 'null', '[{"option": "A. wear a face mask ", "correct": false}, {"option": "B. open windows ", "correct": false}, {"option": "C. wear gloves ", "correct": true}, {"option": "D. take frequent breaks ", "correct": false}, {"option": "E. drink plenty of water", "correct": true}]', 'null', 'null', '[{"content": "<p>1</p>\n"}]', 2);
INSERT INTO public.questions VALUES ('d2470c65-05b5-4009-b62d-2799075252d6', '346fd6f7-7513-41f5-9370-889ecca9aab9', 'matrix', 'Questions 15–18', NULL, '<p>Choose the correct letter, A, B or C</p>
<p>How much does Joan like doing each of the following activities?</p>
', 'other', 'null', 'null', 'null', '{"layoutType": "standard", "legendTitle": null, "matrixItems": [{"itemText": "correspondence", "correctCategoryLetter": "B"}, {"itemText": "fund-raising", "correctCategoryLetter": "C"}, {"itemText": "calling riders", "correctCategoryLetter": "A"}, {"itemText": "organising accounts", "correctCategoryLetter": "C"}], "matrixCategories": [{"categoryText": "She really likes it.", "categoryLetter": "A"}, {"categoryText": "She doesn’t mind it.", "categoryLetter": "B"}, {"categoryText": "She hates it.", "categoryLetter": "C"}]}', '[{"content": "<p>1</p>\n"}]', 2);
INSERT INTO public.questions VALUES ('a9468d88-2f5d-49a5-b439-9ead2384abcb', 'd1c250c9-5a68-4f97-a9dd-d5df43aa2ba5', 'checkbox', 'Questions 21-22', '', '<p data-start="886" data-end="912">Choose <strong>TWO </strong>letters, <strong>A</strong>–<strong>E</strong>.</p>
<p data-start="914" data-end="982">According to the passage, which <strong>TWO </strong>of the following statements about fly ash are true?</p>', 'multiple_choice', 'null', '[{"correct": true, "option_text": "A. Fly ash results in less damage to the environment than Portland cement"}, {"correct": false, "option_text": "B. Fly ash was used by the Romans as an alternative to volcanic ash"}, {"correct": true, "option_text": "C. Fly ash is already used in the production of some concrete"}, {"correct": false, "option_text": "D. All countries have access to fly ash resources"}, {"correct": false, "option_text": "E. Fly ash will soon replace volcanic ash"}]', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">ĐÁP ÁN A: Fly ash results in less damage to the environment than Portland cement. (ĐÚNG)</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn F):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“Some modern concrete no longer contains Portland cement; instead, <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"87\">fly ash is used, which causes fewer greenhouse gas emissions</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc khẳng định việc sử dụng tro bay thay thế cho xi măng Portland giúp tạo ra <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"94\">ít khí thải gây hiệu ứng nhà kính hơn</strong> (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"133\">fewer greenhouse gas emissions</em>). Điều này đồng nghĩa với việc nó ít gây hại cho môi trường hơn (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"229\">less damage to the environment</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">ĐÁP ÁN C: Fly ash is already used in the production of some concrete. (ĐÚNG)</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn F):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“<strong data-path-to-node=\"7,0,0\" data-index-in-node=\"21\">Some modern concrete no longer contains Portland cement; instead, fly ash is used</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ “is used” (đang được sử dụng) cho thấy đây là một thực tế đang diễn ra trong ngành xây dựng hiện đại, không phải là một dự đoán hay kế hoạch trong tương lai. Nó đã và đang được dùng để thay thế xi măng Portland trong một số loại bê tông nhất định.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('783922ce-0b34-4405-9617-763289215abd', 'd1c250c9-5a68-4f97-a9dd-d5df43aa2ba5', 'fillup', 'Questions 23–26', '<p data-start="1419" data-end="1448">Complete the summary below.</p>
<p data-start="1450" data-end="1517">Choose <strong>ONE WORD AND/OR A NUMBER</strong> from the passage for each answer.</p>
<p data-start="1450" data-end="1517"> </p>
<p data-start="1583" data-end="1639"><span style="font-size: 12pt;" role="text"><strong data-start="1587" data-end="1639">The environmental effects of concrete production</strong></span></p>
<p data-start="1641" data-end="2204">Roman concrete is better for the environment than modern concrete, which is made by using Portland cement. This is because a temperature of 1,450 degrees Celsius is needed to combine clays and {limestone} to make Portland cement. This level of heat was reduced by a {third} when making Roman concrete. Needing less heat meant less {fuel} had to be burned and less carbon dioxide was produced. According to Monteiro, when considering the amount of carbon dioxide emitted by {industry}, seven percent of it comes from the manufacture of Portland cement.</p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">23. {limestone}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn E):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“…burning fuel in order to heat a mix of <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"63\">limestone and clays</strong> to 1,450 degrees Celsius.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi yêu cầu tìm loại vật liệu được kết hợp với đất sét (clays) ở nhiệt độ cao để tạo ra xi măng Portland. Trong bài đọc, tác giả nêu rõ hỗn hợp này gồm đá vôi (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"176\">limestone</strong>) và đất sét.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">24. {third}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn E):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“A temperature that was a <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"46\">third</strong> lower than that required for making Portland cement was sufficient for making Roman concrete.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài tóm tắt nói về việc mức nhiệt độ này được giảm đi một khoảng bao nhiêu khi làm bê tông La Mã. Dẫn chứng xác nhận mức nhiệt độ cần thiết thấp hơn một phần ba (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"174\">a third</strong>) so với quy trình hiện đại.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">25. {fuel}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn E):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“…releases carbon dioxide into the atmosphere from <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"73\">burning fuel</strong> in order to heat a mix…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Để tạo ra nhiệt độ cao, người ta phải thực hiện hành động đốt cháy. Từ cần điền ở đây là nhiên liệu (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"113\">fuel</strong>). Việc đốt nhiên liệu ít hơn đồng nghĩa với việc tạo ra ít khí <span class=\"math-inline\" data-math=\"CO_2\" data-index-in-node=\"181\">$CO_2$</span> hơn.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">26. {industry}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn E):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">“…manufacturing Portland cement accounts for seven percent of the carbon dioxide that <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"108\">industry</strong> puts into the air.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi yêu cầu xác định nguồn phát thải khí <span class=\"math-inline\" data-math=\"CO_2\" data-index-in-node=\"57\">$CO_2$</span> mà trong đó sản xuất xi măng chiếm 7%. Văn bản ghi rõ đây là lượng khí thải mà ngành công nghiệp (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"160\">industry</strong>) thải vào không khí.</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('4ae3ea5f-72fd-4895-9ce4-214c6080af0d', 'c043d282-b800-41d8-8e66-ffc2964df044', 'fillup', 'Questions 7–10', '<p data-path-to-node="10">Complete the table below.</p>
<p data-path-to-node="11">Write <strong data-path-to-node="11" data-index-in-node="6">ONE WORD ONLY</strong> for each answer.</p>
<table style="border-collapse: collapse; width: 99.9592%; height: 210.521px; border-spacing: 2px; border: 1px solid #000000;" border="1"><colgroup><col style="width: 25.0109%;"><col style="width: 25.0109%;"><col style="width: 25.0109%;"><col style="width: 25.0109%;"></colgroup>
<tbody>
<tr style="height: 36.5208px;">
